-- ============================================================================
-- 019_certification_seed.sql  —  ~40 sample published questions
-- Idempotent (guarded by the 'seed' tag). Lets the certification flow be tested
-- end-to-end before the admin fills the real 500-question bank. Safe to delete
-- later: `delete from certification_questions where tags @> array['seed'];`
-- ============================================================================

do $$
declare v_quiz uuid := 'c0000000-0000-4000-8000-000000000001';
begin
  if not exists (select 1 from public.certification_questions where quiz_id = v_quiz and tags @> array['seed']) then
  end if;
end $$;
